[CmdletBinding()]
param([Parameter(Mandatory)][string]$ProjectRoot,[Parameter(Mandatory)][string]$Role,[string]$State,[ValidateSet('lean','standard','thorough')][string]$Mode,[string]$Task,[string[]]$AffectedPath=@(),[switch]$Diagnostic,[switch]$Force)
$ErrorActionPreference='Stop';. (Join-Path $PSScriptRoot '../records/Test-RequiredProjectRecords.ps1');. (Join-Path $PSScriptRoot '../security/Test-ProjectRelativePath.ps1')
function Hash([object]$Value){$text=if($Value -is [string]){$Value}else{$Value|ConvertTo-Json -Depth 20 -Compress};(Get-FileHash -InputStream ([IO.MemoryStream]::new([Text.Encoding]::UTF8.GetBytes($text))) -Algorithm SHA256).Hash.ToLowerInvariant()}
function Item([string]$Path,[string]$Category,[string]$Reason){[ordered]@{path=$Path;category=$Category;selectionReason=$Reason;estimatedTokens=[math]::Ceiling((Get-Content -Raw -LiteralPath $Path -ErrorAction SilentlyContinue).Length/4);contentFingerprint=if(Test-Path $Path){Hash (Get-Content -Raw $Path)}else{''}}}
$project=(Resolve-Path $ProjectRoot).Path;$studio=Join-Path $project '.studio';$root=(Resolve-Path (Join-Path $PSScriptRoot '../..')).Path;$v=Test-RequiredProjectRecords $project;$req=$v.requirements;$canonicalState=$req.state.record.metadata.data.currentState;$effectiveMode=$req.workflowMode;if($Mode){$effectiveMode=$Mode};if($State -and $State -ne $canonicalState -and $State -ne 'implementation'){throw 'CONTEXT_STATE_CONFLICT'};if($AffectedPath.Count -and @($AffectedPath|Where-Object{-not(Test-ProjectRelativePath $project $_).valid}).Count){throw 'CONTEXT_PATH_CONFLICT'}
$planPath=Join-Path $studio 'reports/specialist-plan.json';$assignmentPath=Join-Path $studio ('runtime/assignments/'+$Role+'.json');if((-not(Test-Path $assignmentPath)) -and $Task){& (Join-Path $PSScriptRoot '../Resolve-SpecialistPlan.ps1') -ProjectRoot $project -OutputPath $planPath|Out-Null};if(-not(Test-Path $assignmentPath)){throw 'CONTEXT_ASSIGNMENT_MISSING'};$assignment=Get-Content -Raw $assignmentPath|ConvertFrom-Json;if($assignment.status -ne 'ready'){throw 'CONTEXT_ASSIGNMENT_BLOCKED'};if($assignment.role -ne $Role){throw 'CONTEXT_ASSIGNMENT_STALE'};if(-not(Test-Path $planPath)){throw 'CONTEXT_PLAN_STALE'};$plan=Get-Content -Raw $planPath|ConvertFrom-Json;if(-not $Task -and $plan.status -ne 'ready'){throw 'CONTEXT_PLAN_STALE'}
$registry=Get-Content -Raw (Join-Path $root 'knowledge/context/CONTEXT_ROUTE_REGISTRY.json')|ConvertFrom-Json;$route=$registry.roles|Where-Object role -eq $Role;if(-not $route){throw 'CONTEXT_ASSIGNMENT_MISSING'};foreach($path in @($assignment.allowedPaths)){if(-not(Test-ProjectRelativePath $project $path -AllowGlob).valid){throw 'CONTEXT_PATH_CONFLICT'}}
$recordNames=@($route.mandatoryRecords);foreach($prop in $route.conditionalRecords.psobject.Properties){if(@($req.surfaces)-contains $prop.Name){$recordNames+=@($prop.Value)}};$selected=@();$excluded=@();foreach($name in @($recordNames|Sort-Object -Unique)){$path=Join-Path $studio $name;if(Test-Path $path){$selected+=Item $path 'record' 'Mandatory or applicable conditional route record.'}else{$excluded+=[ordered]@{path=$path;category='record';reason='Missing or not applicable.'}}}
$index=Get-Content -Raw (Join-Path $root 'knowledge/context/RULE_ROUTE_INDEX.json')|ConvertFrom-Json;$rules=@($index.rules|Where-Object{($_.roles -contains '*' -or $_.roles -contains $Role) -and ($_.stages -contains '*' -or $_.stages -contains $canonicalState) -and ($_.surfaces.Count -eq 0 -or @($_.surfaces|Where-Object{@($req.surfaces)-contains $_}).Count)}|Sort-Object id);$ruleItems=@($rules|ForEach-Object{[ordered]@{id=$_.id;category='rule';selectionReason='Applicable canonical route rule.';estimatedTokens=[math]::Ceiling($_.summary.Length/4);contentFingerprint=Hash $_}})
$deltas=@();$deltaDir=Join-Path $studio 'reports/deltas';if(Test-Path $deltaDir){foreach($file in Get-ChildItem $deltaDir -Filter '*.json' -File){try{$d=Get-Content -Raw $file|ConvertFrom-Json;if($assignment.predecessors -contains $d.role -or $route.relevantDeltaRoles -contains $d.role){$deltas+=[ordered]@{id=$d.role;category='delta';selectionReason='Predecessor or relevant role delta.';estimatedTokens=[math]::Ceiling((Get-Content -Raw $file).Length/4);contentFingerprint=Hash (Get-Content -Raw $file)}}else{$excluded+=[ordered]@{path=$file.FullName;category='delta';reason='Unrelated delta.'}}}catch{$excluded+=[ordered]@{path=$file.FullName;category='delta';reason='Invalid delta.'}}}}
$mapPath=Join-Path $studio 'REPO_MAP.json';if(-not(Test-Path $mapPath)){& (Join-Path $PSScriptRoot 'build_repo_map.ps1') -ProjectRoot $project|Out-Null};$repo=@($assignment.allowedPaths|Sort-Object);$cards=@();$target=@{lean=8000;standard=16000;thorough=30000}[$effectiveMode];$warning=@{lean=12000;standard=24000;thorough=45000}[$effectiveMode];$contributors=@($selected)+@($ruleItems)+@($deltas);$estimated=0;foreach($contributor in $contributors){if($contributor -and $contributor.PSObject.Properties['estimatedTokens']){$estimated+=[int]$contributor.estimatedTokens}};$fingerprint=Hash ([ordered]@{role=$Role;mode=$effectiveMode;assignment=$assignment;plan=$plan;records=@($selected|ForEach-Object contentFingerprint);rules=@($ruleItems|ForEach-Object contentFingerprint);map=Hash(Get-Content -Raw $mapPath)})
$runtime=Join-Path $studio 'runtime/context';New-Item -ItemType Directory -Force $runtime|Out-Null;$output=Join-Path $runtime ($Role+'.json');$cache='miss';if((Test-Path $output) -and -not $Force){try{$old=Get-Content -Raw $output|ConvertFrom-Json;if($old.schemaVersion -eq 2 -and $old.fingerprint -eq $fingerprint -and $old.workflowMode -eq $effectiveMode){$cache='hit'}}catch{$cache='stale'}};$status=if(-not $v.valid){'blocked'}elseif($estimated -gt $warning){'warning'}else{'ready'};$manifest=[ordered]@{schemaVersion=2;status=$status;role=$Role;workflowMode=$effectiveMode;projectState=$canonicalState;productType=$req.productType;surfaces=@($assignment.surfaces);assignmentPath='.studio/runtime/assignments/'+$Role+'.json';taskIds=@($assignment.taskIds);criteriaIds=@($assignment.criteriaIds);activeScope=@($req.state.record.metadata.data.activeScope);selectedRecords=$selected;selectedRules=$ruleItems;selectedRuleIds=@($ruleItems|ForEach-Object id);selectedReferenceCards=$cards;selectedDeltas=$deltas;repositoryPaths=$repo;excludedItems=$excluded;estimatedTokens=$estimated;targetTokens=$target;warningTokens=$warning;budgetStatus=if($estimated -gt $warning){'exceeded'}elseif($estimated -gt $target){'warning'}else{'within-target'};contributors=$contributors;stages=if($estimated -gt $warning){@('core','contracts','references','history')}else{@('core')};fingerprint=$fingerprint;cacheStatus=$cache;invalidatedBy=@();blockingReasons=@()};$indexPath=Join-Path $studio 'CONTEXT_INDEX.json';Write-AtomicTextFile $project $indexPath (([ordered]@{schemaVersion=1;authoritativeRecords=@($selected|ForEach-Object path);specialistPlan=$planPath;assignments=@($assignmentPath);generatedManifests=@($output);blockers=@()})|ConvertTo-Json -Depth 8);Write-AtomicTextFile $project $output ($manifest|ConvertTo-Json -Depth 20);if($status -eq 'blocked' -and -not $Diagnostic){throw 'CONTEXT_BLOCKED'};Write-Host "Context manifest generated: $output ($status)"
